public class UserCredentialStore {

    public record UserDetails(String username, String encodedPassword, Set<String> roles, boolean locked) {}

    private final Map<String, UserDetails> users = new HashMap<>();
    private final Map<String, Integer> failedAttempts = new HashMap<>();
    private final int maxFailedAttempts;

    public UserCredentialStore(int maxFailedAttempts) {
        this.maxFailedAttempts = maxFailedAttempts;
    }

    public void registerUser(String username, String rawPassword, Set<String> roles) {
        // Hash the password (use simple hash: charsum) and store user as unlocked
        int hash = rawPassword.chars().sum();
        users.put(username, new UserDetails(username, String.valueOf(hash), roles, false));
    }

    public boolean authenticate(String username, String rawPassword) {
        // Return false if user not found or account locked
        // Verify password; on failure increment failedAttempts and lock if threshold reached
        // On success, reset failedAttempts
        return false;
    }

    public boolean isLocked(String username) {
        UserDetails user = users.get(username);
        return user != null && user.locked();
    }

    public static void main(String[] args) {
        UserCredentialStore store = new UserCredentialStore(3);
        store.registerUser("bob", "pass123", Set.of("USER"));

        System.out.println(store.authenticate("bob", "pass123")); // true
        store.authenticate("bob", "wrong");
        store.authenticate("bob", "wrong");
        store.authenticate("bob", "wrong");
        System.out.println("Locked: " + store.isLocked("bob"));   // true
